select count(*) from postgres.comments as c, postgres.posts as p, postgres.posthistory as ph, postgres.votes as v, postgres.users as u where v.userid = u.id and c.userid = u.id and p.owneruserid = u.id and ph.userid = u.id and c.score=2 and p.answercount>=0 and p.answercount<=9 and p.creationdate>=timestamp '2010-07-20 18:17:25' and p.creationdate<=timestamp '2014-08-26 12:57:22' and ph.creationdate<=timestamp '2014-09-02 07:58:47' and v.bountyamount>=0 and v.creationdate>=timestamp '2010-05-19 00:00:00' and u.upvotes<=230 and u.creationdate>=timestamp '2010-09-22 01:07:10' and u.creationdate<=timestamp '2014-08-15 05:52:23';
